import { useEffect, useState } from "react";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads);
        fetch("/api/news").then(res => res.json()).then(setNews);
        fetch("/api/matches").then(res => res.json()).then(data => {console.log("API matches data:", data);
                if (Array.isArray(data)) { setMatches(data); } else if (data.content) {
                    setMatches(data.content);
                } else {
                    setMatches([]);
                }
            })
            .catch(err => {
                console.error("Failed to fetch matches:", err);
                setMatches([]);
            });
        fetch("/api/events").then(res => res.json()).then(setEvents);
    }, []);

    return (
        <main style={styles.Dashboard}>
        <div style={{display: 'flex', gap: '20px'}}>

            {/* 1st Column: Threads */}
            <div style={{flex: 1}}>
                <h3>Threads</h3>
                {threads.map((thread, idx) => (
                    <div
                        key={idx}
                        onClick={() => alert(`Clicked thread: ${thread.title}`)}
                        style={{
                            border: '1px solid #ccc',
                            padding: '10px',
                            marginBottom: '1px',
                            borderRadius: '0px',
                            cursor: 'pointer',
                            backgroundColor: '#f9f9f9',
                            transition: 'background-color 0.3s ease',
                        }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#e0e0e0')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = '#f9f9f9')}
                    >
                        {thread.title}
                    </div>
                ))}
            </div>

            {/* 2nd Column: News */}
            <div style={{flex: 1}}>
                <h3>News</h3>
                {news.map((item, idx) => (
                    <div
                        key={idx}
                        onClick={() => alert(`Clicked news: ${item.headline}`)}
                        style={{
                            border: '1px solid #ccc',
                            padding: '10px',
                            marginBottom: '10px',
                            borderRadius: '0px',
                            cursor: 'pointer',
                            backgroundColor: '#f9f9f9',
                            transition: 'background-color 0.3s ease',
                        }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#e0e0e0')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = '#f9f9f9')}
                    >
                        {item.headline}
                    </div>
                ))}
            </div>

            {/* 3rd Column: Matches */}
            <div style={{flex: 1}}>
                <h3>Matches</h3>
                {matches.map((match, idx) => (
                    <div
                        key={idx}
                        onClick={() => alert(`Clicked match: ${match.teama} vs ${match.teamb}`)}
                        style={{
                            border: '1px solid #ccc',
                            padding: '10px',
                            marginBottom: '10px',
                            borderRadius: '0px',
                            cursor: 'pointer',
                            backgroundColor: '#f9f9f9',
                            transition: 'background-color 0.3s ease',
                        }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#e0e0e0')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = '#f9f9f9')}
                    >
                        {match.teama} vs {match.teamb} <br/>
                        <small>{new Date(match.match_time).toLocaleString()}</small>
                    </div>
                ))}
            </div>

            {/* 4th Column: Events */}
            <div style={{flex: 1}}>
                <h3>Events</h3>
                {events.map((event, idx) => (
                    <div
                        key={idx}
                        onClick={() => alert(`Clicked event: ${event.name}`)}
                        style={{
                            border: '1px solid #ccc',
                            padding: '10px',
                            marginBottom: '10px',
                            borderRadius: '0px',
                            cursor: 'pointer',
                            backgroundColor: '#f9f9f9',
                            transition: 'background-color 0.3s ease',
                        }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#e0e0e0')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = '#f9f9f9')}
                    >
                        {event.name} <br/>
                        <small>{new Date(event.event_date_time).toLocaleString()}</small>
                    </div>
                ))}
            </div>
        </div>
        </main>
    );
}

const styles = {
    Dashboard: {
        paddingTop: '0',
    }
}

export default Dashboard;
